#include <vector>
using namespace std;

class DSU {
    vector<int> parent, rank;
public:
    DSU(int n) {
        parent.resize(n);
        rank.resize(n,0);
        for(int i=0;i<n;i++) parent[i]=i;
    }
    int find(int x) {
        if(parent[x]!=x)
            parent[x]=find(parent[x]);
        return parent[x];
    }
    void unite(int x,int y) {
        int px=find(x), py=find(y);
        if(px==py) return;
        if(rank[px]<rank[py]) parent[px]=py;
        else if(rank[py]<rank[px]) parent[py]=px;
        else { parent[py]=px; rank[px]++; }
    }
};

#include <iostream>
using namespace std;

void floyd(int dist[][100], int V) {
    for(int k=0;k<V;k++)
        for(int i=0;i<V;i++)
            for(int j=0;j<V;j++)
                if(dist[i][k]+dist[k][j] < dist[i][j])
                    dist[i][j] = dist[i][k]+dist[k][j];
}

#include <vector>
#include <stack>
using namespace std;

void dfs1(int v, vector<int> adj[], vector<bool>& vis, stack<int>& st) {
    vis[v]=true;
    for(int u: adj[v]) if(!vis[u]) dfs1(u,adj,vis,st);
    st.push(v);
}

#include <vector>
using namespace std;

void dfsBridge(int u, int parent, vector<int> adj[], vector<int>& disc, vector<int>& low, int& time) {
    disc[u]=low[u]=++time;
    for(int v: adj[u]) {
        if(v==parent) continue;
        if(!disc[v]) {
            dfsBridge(v,u,adj,disc,low,time);
            low[u]=min(low[u],low[v]);
            if(low[v]>disc[u]) cout<<u<<"-"<<v<<" bridge\n";
        } else low[u]=min(low[u],disc[v]);
    }
}

#include <queue>
#include <vector>
using namespace std;

bool isBipartite(int V, vector<int> adj[]) {
    vector<int> color(V,-1);
    for(int i=0;i<V;i++) {
        if(color[i]==-1) {
            queue<int> q;
            q.push(i);
            color[i]=0;
            while(!q.empty()) {
                int u=q.front(); q.pop();
                for(int v: adj[u]) {
                    if(color[v]==-1) {
                        color[v]=!color[u];
                        q.push(v);
                    } else if(color[v]==color[u]) return false;
                }
            }
        }
    }
    return true;
}
